import React from 'react';

const Electronics = () => (
  <div className="pt-24 min-h-screen bg-white p-10">
    <h1 className="text-4xl font-bold text-gray-800 border-b-4 border-blue-600 inline-block mb-6">Electronics Industry</h1>
    <p className="text-gray-600 text-lg">We provide specialized manpower for semiconductor manufacturing, PCB assembly, and consumer electronics R&D.</p>
  </div>
);

export default Electronics;
